@import"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700&display=swap";*{box-sizing:border-box;margin:0;padding:0}.app-root{width:100%;height:600px;background:linear-gradient(160deg, #0f0c1a 0%, #1a1028 50%, #0d1520 100%);font-family:"Noto Sans SC","PingFang SC","Microsoft YaHei",sans-serif;border-radius:20px;overflow:hidden;color:#e8e0f0;display:flex;flex-direction:column;position:relative}.status-bar{display:flex;align-items:center;justify-content:space-between;padding:10px 14px 8px;background:hsla(0,0%,100%,.03);border-bottom:1px solid hsla(0,0%,100%,.06);gap:6px}.status-left,.status-right{display:flex;gap:5px;align-items:center}.status-center{flex:1;display:flex;justify-content:center}.date-chip,.week-chip,.weather-chip{font-size:10px;padding:2px 7px;border-radius:20px;background:hsla(0,0%,100%,.07);color:#b8a8d0;letter-spacing:.3px}.time-badge{font-size:11px;font-weight:600;padding:3px 10px;border-radius:20px;background:linear-gradient(90deg, rgba(168, 85, 247, 0.25), rgba(99, 102, 241, 0.25));border:1px solid rgba(168,85,247,.3);color:#d8b4fe;letter-spacing:.5px}.history-btn{width:24px;height:24px;border-radius:50%;border:none;background:hsla(0,0%,100%,.07);color:#6b5f80;font-size:11px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all .15s}.history-btn.active,.history-btn:hover{background:rgba(167,139,250,.2);color:#a78bfa}.thinking-bar{display:flex;align-items:center;gap:8px;padding:8px 14px;font-size:12px;color:#7c6f96;background:rgba(167,139,250,.05);border-bottom:1px solid rgba(167,139,250,.1)}.thinking-spin{color:#a78bfa;font-size:13px}.tab-bar{display:flex;padding:0 8px;gap:4px;margin-top:8px;background:rgba(0,0,0,.2);border-bottom:1px solid hsla(0,0%,100%,.05)}.tab-btn{flex:1;display:flex;align-items:center;justify-content:center;gap:5px;padding:9px 4px;border:none;background:rgba(0,0,0,0);color:#6b5f80;font-size:12px;font-weight:500;cursor:pointer;transition:all .2s;border-bottom:2px solid rgba(0,0,0,0)}.tab-btn i{font-size:11px}.tab-btn.active{color:#c084fc;border-bottom-color:#c084fc;background:rgba(192,132,252,.06)}.tab-content{flex:1;overflow-y:auto;min-height:0;padding:12px}.input-bar{display:flex;gap:8px;padding:10px 12px 12px;border-top:1px solid hsla(0,0%,100%,.07);background:rgba(0,0,0,.2)}.input-field{flex:1;background:hsla(0,0%,100%,.07);border:1px solid hsla(0,0%,100%,.1);border-radius:20px;padding:9px 14px;color:#e8e0f0;font-size:13px;outline:none;font-family:inherit}.input-field::placeholder{color:#4a4060}.input-field:focus{border-color:rgba(168,85,247,.5)}.input-field:disabled{opacity:.5}.send-btn{width:38px;height:38px;border-radius:50%;border:none;flex-shrink:0;background:linear-gradient(135deg, #7c3aed, #a78bfa);color:#fff;font-size:13px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:opacity .15s}.send-btn:disabled{opacity:.4;cursor:not-allowed}.history-panel{position:absolute;inset:0;z-index:200;background:rgba(0,0,0,.6);backdrop-filter:blur(4px);display:flex;flex-direction:column}.history-inner{margin:auto 0 0;max-height:75%;background:linear-gradient(160deg, #1a1028, #0f0c1a);border-top:1px solid hsla(0,0%,100%,.1);border-radius:20px 20px 0 0;display:flex;flex-direction:column;overflow:hidden}.history-header{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;font-size:13px;font-weight:700;color:#c084fc;border-bottom:1px solid hsla(0,0%,100%,.07);flex-shrink:0}.h-count{font-size:10px;color:#6b5f80;font-weight:400;margin-left:4px}.h-close{background:none;border:none;color:#6b5f80;font-size:14px;cursor:pointer}.h-loading,.h-empty{padding:24px;text-align:center;font-size:12px;color:#4a3f60}.h-list{overflow-y:auto;padding:8px;display:flex;flex-direction:column;gap:6px}.h-item{border-radius:10px;padding:10px 12px}.h-item.user{background:rgba(99,102,241,.08);border-left:2px solid rgba(99,102,241,.4)}.h-item.assistant{background:rgba(167,139,250,.08);border-left:2px solid rgba(167,139,250,.4)}.h-item.hidden{opacity:.6}.h-item-head{display:flex;align-items:center;gap:6px;margin-bottom:5px}.h-role{font-size:10px;font-weight:700;color:#7c6f96}.h-id{font-size:10px;color:#4a3f60;flex:1}.h-hidden-tag{font-size:9px;padding:1px 5px;border-radius:6px;background:rgba(251,191,36,.15);color:#fbbf24;border:1px solid rgba(251,191,36,.3)}.h-expand{background:none;border:none;color:#4a3f60;font-size:10px;cursor:pointer;padding:2px 4px}.h-expand:hover{color:#a78bfa}.h-rollback{font-size:10px;padding:2px 8px;border-radius:10px;border:none;background:rgba(239,68,68,.15);color:#f87171;cursor:pointer;display:flex;align-items:center;gap:4px}.h-rollback:hover{background:rgba(239,68,68,.25)}.h-content{font-size:12px;color:#9d8fb0;line-height:1.6;white-space:pre-wrap;max-height:72px;overflow:hidden;display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical}.h-content.expanded{max-height:none;display:block;-webkit-line-clamp:unset}.debug-panel{position:absolute;inset:0;z-index:300;background:#0a0a0f;display:flex;flex-direction:column}.debug-header{display:flex;align-items:center;justify-content:space-between;padding:8px 12px;font-size:12px;font-weight:700;color:#34d399;border-bottom:1px solid rgba(52,211,153,.2);flex-shrink:0}.debug-pre{flex:1;overflow-y:auto;padding:10px 12px;font-size:11px;line-height:1.6;color:#9d8fb0;white-space:pre-wrap;word-break:break-all;font-family:"Courier New",monospace}